function longestConsecutiveSequenceBruteForce(numbers) {
  let longestSequenceLength = 0;

  for (let i = 0; i < numbers.length; i++) {
    let currentNumber = numbers[i];
    let currentSequenceLength = 1;

    // Start checking for the next consecutive number
    while (true) {
      let nextNumber = currentNumber + 1;
      let foundNextNumber = false;

      for (let j = 0; j < numbers.length; j++) {
        if (numbers[j] === nextNumber) {
          foundNextNumber = true;
          break;
        }
      }

      // If next number exists, extend the sequence
      if (foundNextNumber) {
        currentSequenceLength++;
        currentNumber = nextNumber;
      } else {
        break;
      }
    }

    // Update the maximum length if needed
    if (currentSequenceLength > longestSequenceLength) {
      longestSequenceLength = currentSequenceLength;
    }
  }

  return longestSequenceLength;
}

