public class Solution {
    public int longestConsecutive(int[] numbers) {
        int longestSequenceLength = 0;

        for (int currentNumber : numbers) {
            int currentSequenceLength = 1;
            int nextNumber = currentNumber + 1;

            // Check if the next number in the sequence exists
            while (contains(numbers, nextNumber)) {
                currentSequenceLength++;
                nextNumber++;
            }

            // Update the longest sequence length if needed
            if (currentSequenceLength > longestSequenceLength) {
                longestSequenceLength = currentSequenceLength;
            }
        }

        return longestSequenceLength;
    }

    private boolean contains(int[] numbers, int numberToCheck) {
        // Linear search to find if a number exists
        for (int number : numbers) {
            if (number == numberToCheck) {
                return true;
            }
        }
        return false;
    }
}

