            if (numberSet.contains(number - 1)) {
                continue;
            }

            int currentNumber = number;
            int currentSequenceLength = 1;

            //Build the sequence from the start.
            while (numberSet.contains(currentNumber + 1)) {

                currentNumber += 1;
                currentSequenceLength += 1;
            }

            //Keep track of the longest sequence.
            longestSequenceLength = Math.max(longestSequenceLength, currentSequenceLength);

        }

        return longestSequenceLength;
    }
}

