int longestConsecutive(std::vector<int>& numbers) {
    std::unordered_set<int> numberSet(numbers.begin(), numbers.end());
    int longestSequenceLength = 0;

    for (int number : numbers) {
        // Only process numbers that could be sequence starts.
        if (numberSet.find(number - 1) == numberSet.end()) {

            int currentNumber = number;
            int currentSequenceLength = 1;

            // Build the sequence as long as consecutive numbers exist.
            while (numberSet.find(currentNumber + 1) != numberSet.end()) {
                currentNumber++;
                currentSequenceLength++;
            }

            // Track the overall longest sequence found.
            if (currentSequenceLength > longestSequenceLength) {
                longestSequenceLength = currentSequenceLength;
            }
        }
    }

    return longestSequenceLength;
}

